import{_ as a,a as t,b as n,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as i,c,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup and Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/redundant-backup-and-read-source.md","filePath":"en/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"en/Other/redundant-backup-and-read-source.md"};function h(p,e,o,u,b,k){return i(),c("div",null,[...e[0]||(e[0]=[s('<h1 id="redundant-backup-and-read-source-switching" tabindex="-1">Redundant Backup and Read Source Switching <a class="header-anchor" href="#redundant-backup-and-read-source-switching" aria-label="Permalink to &quot;Redundant Backup and Read Source Switching&quot;">​</a></h1><p>Redundant backup stores an extra copy of an already uploaded file.</p><p>Both the primary file and the backup file can be used as read sources. Visitors normally see no difference. The only difference is which storage channel serves the file.</p><h2 id="what-redundant-backup-can-do" tabindex="-1">What Redundant Backup Can Do <a class="header-anchor" href="#what-redundant-backup-can-do" aria-label="Permalink to &quot;What Redundant Backup Can Do&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Store an extra copy</td><td>Back up files to another upload channel to reduce the risk of a single channel failure.</td></tr><tr><td>Switch read source</td><td>After backup succeeds, switch file reads between the primary channel and backup channel.</td></tr><tr><td>Single-file backup</td><td>Back up one file from its file details page.</td></tr><tr><td>Batch backup</td><td>Select multiple files in the admin page and back them up together.</td></tr><tr><td>Global redundant backup</td><td>Back up files by folder from Other Settings.</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+a+'" alt="Redundant backup" loading="lazy"></p><p>This entry is best for adding backups to a folder or to all files in bulk.</p><p>The backup channel can be selected manually, or you can choose automatic switching and let ImgBed find a suitable backup channel.</p><h2 id="backup-from-file-details" tabindex="-1">Backup From File Details <a class="header-anchor" href="#backup-from-file-details" aria-label="Permalink to &quot;Backup From File Details&quot;">​</a></h2><p>Open a file details page in the admin panel and click backup.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>This is best for backing up one important file on demand.</p><p>After backup succeeds, the file details page shows available read sources.</p><h2 id="batch-backup-by-selection" tabindex="-1">Batch Backup by Selection <a class="header-anchor" href="#batch-backup-by-selection" aria-label="Permalink to &quot;Batch Backup by Selection&quot;">​</a></h2><p>In the admin panel, select multiple files and run batch backup.</p><p><img src="'+n+'" alt="Batch backup" loading="lazy"></p><p>This is best for processing a group of files.</p><p>Selection backup, file details backup, and redundant backup under Other Settings all use the same backup system. They are just different entry points.</p><h2 id="switching-read-source-after-backup" tabindex="-1">Switching Read Source After Backup <a class="header-anchor" href="#switching-read-source-after-backup" aria-label="Permalink to &quot;Switching Read Source After Backup&quot;">​</a></h2><p>After backup completes, the file details page lets you switch read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Reads from the original upload channel.</td></tr><tr><td>Backup channel</td><td>Reads from the backup channel.</td></tr></tbody></table><p><img src="'+r+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors do not need to know whether the file is served from the primary or backup channel.</p><p>Whichever read source you choose becomes the preferred source for later file access.</p><h2 id="when-backup-is-skipped" tabindex="-1">When Backup Is Skipped <a class="header-anchor" href="#when-backup-is-skipped" aria-label="Permalink to &quot;When Backup Is Skipped&quot;">​</a></h2><p>The following cases are skipped during backup. They are not errors.</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>A file that already has a backup is not backed up again.</td></tr><tr><td>Primary and backup channels are the same</td><td>A backup must be stored in another channel to be meaningful.</td></tr><tr><td>No usable backup channel</td><td>No suitable alternative channel is available.</td></tr></tbody></table><p>In short: backups must go to another channel, and already backed-up files do not consume extra space again.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>The channel used when the file was first uploaded.</td></tr><tr><td>Backup channel</td><td>The channel that stores the redundant copy.</td></tr><tr><td>Primary read source</td><td>The file is currently read from the primary channel.</td></tr><tr><td>Backup read source</td><td>The file is currently read from the backup channel.</td></tr></tbody></table><p>Primary and backup read sources have the same user-facing behavior.</p><p>As long as the backup file is available, images, videos, and download links continue to work after switching to the backup read source.</p><h2 id="what-happens-when-a-file-is-deleted" tabindex="-1">What Happens When a File Is Deleted <a class="header-anchor" href="#what-happens-when-a-file-is-deleted" aria-label="Permalink to &quot;What Happens When a File Is Deleted&quot;">​</a></h2><p>When a file is deleted, ImgBed deletes both the primary file and the backup file.</p>',37)])])}const g=d(l,[["render",h]]);export{y as __pageData,g as default};
